4874	<html>\n   <head>\n     <!-- Solar system: /static/main/images/solarsystem.jpg -->\n     <style>\n        body {\n           background-image: url(/static/main/images/solarsystem.jpg);\n           background-size: cover;\n           background-position: center;\n           text-align:center;\n        }\n        button{background:linear gradient();\n        font-family:serif;\n            \n        }\n        table{\n            margin:o auto;\n            background:rgba(225,225,225,0.5);\n            font-size:30px;\n            \n        }\n        input{\n            text-align:center;\n        }\n        h1,h2{background:rgba(225,225,225,0.7);\n        }\n       h1 {\n            text-align:center;\n        }\n        \n        \n     </style>\n   </head>\n   <body>\n       <h1>Kila Sayari Ina Miezi Mingapi?</h1>\n       <center>\n       <table>\n           <tr><th>Sayari</th><th>Miezi Mingapi</th></tr>\n           <tr><td>Mercury</td><td><input value="0"></td></tr>\n           <tr><td>Venus</td><td><input value="0"></td></tr>\n           <tr><td>Earth</td><td><input value="1"></td></tr>\n            <tr><td>Mars</td><td><input  value="2"></td></tr>\n           <tr><td>Jupiter</td><td><input value="67"></td></tr>\n           <tr><td>Saturn</td><td><input value="62"></td></tr>\n           <tr><td>Uranus</td><td><input value="27"></td></tr>\n           <tr><td>Neptune</td><td><input value="14"></td></tr>\n           <tr><td>Pluto</td><td><input value="5"></td></tr>\n           </table>\n           </center>\n           <p><button id='calculate'>HESABU JUMLA</button></p>\n           <h1>Jumla ya miezi:<span id="output"></span></h1>\n     <script>\n       document.getElementById('calculate').onclick = function() {\n         var inputs = document.getElementsByTagName("input");\n         var sum=0;\n         Array.prototype.forEach.call(inputs, function(input, index, arr) {\n            sum+=parseInt(input.value);\n         });\n         var output =document.getElementById("output")\n         output.innerText=sum;\n       };\n     </script>\n   </body>\n</html>	2018-04-20 08:56:56.007463+00	2018-04-25 09:17:01.274692+00	27	19	t
